// Filter: Status = 'Email 2 Sent' AND 4+ days elapsed.
const results = [];
for (const item of $input.all()) {
  const status = (item.json.Status || '').trim();
  if (status !== 'Email 2 Sent' && status !== 'Email 2 Sent (Simulated)') continue;
  const sentAt = item.json['Email 2 Sent At'] || item.json.email2SentAt;
  if (sentAt && (new Date() - new Date(sentAt)) >= 4 * 24 * 60 * 60 * 1000) {
    results.push({ json: item.json });
  }
}
return results;

// Collapse to single trigger for Blacklist Lookup (prevents rate limit)
if ($itemIndex === 0) {
  return [{ json: { _blacklistTrigger: true } }];
}
return [];

const items = $input.all();
const blacklistEmails = items
  .filter(r => r.json && !r.json.error && !r.json._blacklistTrigger)
  .map(r => (r.json.Email || r.json.email || '').toLowerCase().trim())
  .filter(Boolean);
let leads = [];
try { leads = $('Filter: 4+ Days Passed').all(); } catch(e) { leads = []; }
if (leads.length === 0) return [{ json: { _noLeads: true, _blacklistEmails: [] } }];
return leads.map(leadItem => ({ json: { ...leadItem.json, _blacklistEmails: blacklistEmails } }));

const clean = [];
for (const item of $input.all()) {
  const { _blacklistEmails, _noLeads, ...leadData } = item.json;
  if (_noLeads) continue;
  const blacklist = Array.isArray(_blacklistEmails) ? _blacklistEmails : [];
  const email = (leadData.Email || leadData.email || '').toLowerCase().trim();
  if (email && blacklist.includes(email)) continue;
  clean.push({ json: { ...leadData } });
}
return clean;

// Merge thread details with lead data
const threads = $input.all();
const leads = $('Blacklist Gate').all();
return threads.map((item, idx) => {
  const thread = item.json;
  const lead = leads[idx] ? leads[idx].json : {};
  const messages = thread.messages || [];
  const lastMsg = messages.length > 0 ? messages[messages.length - 1] : {};
  const replyBody = (lastMsg.snippet || lastMsg.text || thread.snippet || '').toLowerCase();
  const hasReply = messages.length >= 2;
  const unsubKeywords = ['unsubscribe', 'remove me', 'stop emailing', 'opt out', 'take me off'];
  const isUnsubscribe = unsubKeywords.some(kw => replyBody.includes(kw));
  return { json: { ...lead, replyBody, hasReply, isUnsubscribe, isActionable: hasReply || isUnsubscribe } };
});

return $input.all().map(item => {
  const replyBody = (item.json.replyBody || '').toLowerCase();
  const bounceSignals = ['undeliverable', 'delivery failed', 'delivery status notification', 'returned mail', 'recipient address rejected', 'user unknown', 'no such user', 'mailbox full', 'address not found'];
  const matchedSignal = bounceSignals.find(s => replyBody.includes(s));
  return { json: { ...item.json, isBounce: !!matchedSignal, bounceSignal: matchedSignal || null } };
});

const aiItems = $input.all();
const leads = $('Bounce Detection').all();
return aiItems.map((item, idx) => {
  const lead = leads[idx] ? leads[idx].json : {};
  if (lead.isBounce) return null;
  let intentData = {};
  try {
    const content = item.json.message?.content || item.json.choices?.[0]?.message?.content || '{}';
    intentData = JSON.parse(String(content).replace(/```json\n?/g,'').replace(/```/g,'').trim());
  } catch(e) {
    intentData = { intent: 'NOT_INTERESTED', summary: 'parse error', confidence: 0 };
  }
  return { json: {
    ...lead,
    intent: intentData.intent || 'NOT_INTERESTED',
    summary: intentData.summary || '',
    confidence: intentData.confidence || 0,
    'AI Summary': intentData.summary || '',
    'Replied At': new Date().toISOString()
  } };
}).filter(x => x !== null);

